21	// shortenRunStageWaitPoll lowers the stage long-poll re-read interval for
22	// the duration of a test so the ?wait loop reacts in milliseconds, and
23	// restores it on cleanup. Mirrors shortenScopeAmendmentPoll.
24	func shortenRunStageWaitPoll(t *testing.T) {
25		t.Helper()
26		prev := runStageWaitPollInterval
27		runStageWaitPollInterval = 5 * time.Millisecond
28		t.Cleanup(func() { runStageWaitPollInterval = prev })
