31	// waitStageRepo wraps the shared orchestratorRepo so the wait-loop tests
32	// can (a) read stages as copies — snapshotted under the orchestrator's
33	// lock — so a concurrent state mutation is race-free under -race, and
34	// (b) inject a transient GetStage error on a chosen re-poll to exercise
35	// the best-effort last-good return path. Embedding gives the full
36	// run.Repository for free.
37	type waitStageRepo struct {
38		*orchestratorRepo
39		mu         sync.Mutex
40		getCalls   int
41		failOnCall int // 1-based; once getCalls reaches this, GetStage errors. 0 = never.
42	}
43	
44	func newWaitStageRepo() *waitStageRepo {
45		return &waitStageRepo{orchestratorRepo: newOrchestratorRepo()}
46	}
47	
48	func (r *waitStageRepo) GetStage(ctx context.Context, id uuid.UUID) (*run.Stage, error) {
49		r.mu.Lock()
50		r.getCalls++
51		n := r.getCalls
52		fail := r.failOnCall
53		r.mu.Unlock()
54		if fail > 0 && n >= fail {
55			return nil, errors.New("transient db error")
56		}
57		st, err := r.orchestratorRepo.GetStage(ctx, id)
58		if err != nil {
59			return nil, err
60		}
61		// Snapshot under the orchestrator lock: the live pointer is mutated
62		// by setStageState / TransitionStage from the test's goroutine.
63		r.orchestratorRepo.mu.Lock()
64		cp := *st
65		r.orchestratorRepo.mu.Unlock()
66		return &cp, nil
67	}
