69	// setStageState mutates a seeded stage's state under the orchestrator's
70	// lock so it races cleanly with the wait loop's snapshotting GetStage.
71	func (r *waitStageRepo) setStageState(st *run.Stage, state run.StageState) {
72		r.orchestratorRepo.mu.Lock()
73		st.State = state
74		r.orchestratorRepo.mu.Unlock()
75	}
